+    /// Matches `pd.Series.align(other, join='inner'|'left'|'right'|'outer')`.
+    /// Uses first-match semantics for duplicate labels (same as arithmetic ops).
+    pub fn align(&self, other: &Self, mode: AlignMode) -> Result<(Self, Self), FrameError> {
